  Future<void> _analyzeImage(String imageUrl) async {
    final googleApiKey = await _storage.read(key: 'googleApiKey');
    final response = await http.post(
      Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=$googleApiKey'),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode({
        'requests': [
          {
            'image': {'source': {'imageUri': imageUrl}},
            'features': [{'type': 'LABEL_DETECTION', 'maxResults': 10}],
          }
        ]
      }),
    );

    final result = jsonDecode(response.body);
    setState(() {
      _analysisResult = result['responses'][0]['labelAnnotations']
          .map((annotation) => annotation['description'])
          .join(', ');
    });
  }

